+    class Pump extends Thread {
+      final InputStream src;
+      final OutputStream dst;
+      Pump(InputStream src, OutputStream dst) {
+        this.src = src;
+        this.dst = dst;
+      }
+      @Override
+      public void run() {
+        byte[] buffer = new byte[512];
+        while (true) {
+          try {
+            int l = src.read(buffer);
+            if (l == -1) {
+              break;
+            }
+            dst.write(buffer, 0, l);
+          } catch (IOException e) {
+            break;
+          }
+        }
+      }
+    }
+
